<template>
  <div class="columns is-centered">
    <div class="column is-two-thirds-desktop">
      <hr>
      <p class="has-text-weight-bold has-text-grey-light content is-5">
        <i class="fas fa-map-marked-alt"></i>
        {{message}}
      </p>
      <div class="columns">
        <div class="column">
          <b-field grouped>
            <b-field label="Street" style="flex: 1">
              <b-input ref="checkAdd1" :icon="icon" expanded v-model="main" id="autocomplete" :required="required"></b-input>
            </b-field>
            <b-field label="Unit">
              <b-input :icon="icon" v-model="unit" placeholder="If applicable"></b-input>
            </b-field>
          </b-field>
        </div>
      </div>
      <div class="columns">
        <div class="column is-one-third-desktop">
          <b-field label="City">
            <b-input ref="checkAdd2" v-model="city" :icon="icon" :required="required"></b-input>
          </b-field>
        </div>
        <div class="column is-one-third-desktop">
          <b-field label="Province">
            <b-input :disabled="disabled" :icon="icon" value="Ontario" v-model="province">Ontario</b-input>
          </b-field>
        </div>
        <div class="column is-one-third-desktop">
          <b-field label="Postal code">
            <b-input ref="checkAdd3" :icon="icon" v-model="postal" :required="required"></b-input>
          </b-field>
        </div>
      </div>
      <hr>
    </div>
  </div>
</template>

<script>
export default {
  mounted() {
    let retries = 10;

    let getGoogle = setTimeout(() => {
      if (google) {
        this.autocomplete = new google.maps.places.Autocomplete(
          document.getElementById("autocomplete"),
          { types: ["geocode"] }
        );
        this.autocomplete.addListener("place_changed", this.fillInAddress);
        clearTimeout(getGoogle);
      } else {
        retries -= 1;
        if (retries === 0) {
          clearTimeout(getGoogle);
        }
      }
    }, 250);
  },
  props: {
    form: Object,
    icon: String,
    message: String,
    disabled: Boolean,
    required: Boolean
  },
  computed: {
    main: {
      get() {
        return this.form.main;
      },
      set(val) {
        this.form.main = val;
      }
    },
    unit: {
      get() {
        return this.form.unit;
      },
      set(val) {
        this.form.unit = val;
      }
    },
    city: {
      get() {
        return this.form.city;
      },
      set(val) {
        this.form.city = val;
      }
    },
    province: {
      get() {
        return this.form.province;
      },
      set(val) {
        this.form.province = val;
      }
    },
    postal: {
      get() {
        return this.form.postal;
      },
      set(val) {
        this.form.postal = val;
      }
    }
  },
  methods: {
    fillInAddress() {
      let place = this.autocomplete.getPlace();
      let deets = place.address_components;
      this.form.main = `${deets[0].long_name} ${deets[1].long_name}`;
      this.form.city = deets[2].long_name;
      this.form.province = deets[5].long_name;
      this.form.postal = deets[7].long_name;
    }
  }
};
</script>