<template>
  <div class="the-form" :class="thanks">
    <main-nav></main-nav>

    <transition name="fadeInUp">
      <backdrop v-if="notHome"></backdrop>
    </transition>

    <transition name="fadeUp" mode="out-in">
      <router-view></router-view>
    </transition>
  </div>
</template>

<script>
import Home from "./views/Home.vue";
import backdrop from "./components/backdrop.vue";
import mainNav from "./components/main-nav.vue";
import router from "./router";

export default {
  beforeCreate() {
    this.$store.commit("initState");
  },
  created() {
    try {
      router.push(localStorage.getItem("route"));

      if (!localStorage.getItem("baseGirafoState")) {
        localStorage.setItem(
          "baseGirafoState",
          JSON.stringify(this.$store.state)
        );
      }
    } catch (error) {
      console.log(error);
    }
  },
  updated() {
    localStorage.setItem("route", this.$route.path);
  },
  components: {
    Home,
    backdrop,
    mainNav
  },
  computed: {
    notHome() {
      return this.$route.path !== "/";
    },
    thanks() {
      if (this.$route.path === "/thank-you") {
        return 'thanks';
      }
    }
  }
  // watch: {
  // $route: function(route) {
  // if (route.path === "/-1") {
  //   router.push("/start");
  // }
  // }
  // }
};
</script>

